import fs from "node:fs/promises";
import path from "node:path";
import process from "node:process";

const repoRoot = process.cwd();
const GENERATED_HEADER =
  "// AUTO-GENERATED from cli/kits/blocks by scripts/sync-kit-to-packages.mjs\n// Do not edit this file directly. Edit the kit source instead.\n\n";

function normalizePath(p) {
  return p.replace(/\\/g, "/");
}

async function exists(filepath) {
  try {
    await fs.access(filepath);
    return true;
  } catch {
    return false;
  }
}

async function walkFiles(dir) {
  const entries = await fs.readdir(dir, { withFileTypes: true });
  const files = [];

  for (const entry of entries) {
    const fullPath = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      files.push(...(await walkFiles(fullPath)));
    } else {
      files.push(fullPath);
    }
  }

  return files;
}

function parseArgs(argv) {
  const args = { check: false, force: false, scope: "all", verbose: false };

  for (let i = 0; i < argv.length; i += 1) {
    const arg = argv[i];
    if (arg === "--check") args.check = true;
    else if (arg === "--force") args.force = true;
    else if (arg === "--verbose") args.verbose = true;
    else if (arg === "--scope") args.scope = argv[i + 1] ?? "all";
  }

  if (!["all", "core", "sections", "templates"].includes(args.scope)) {
    throw new Error(`Invalid --scope value: ${args.scope}`);
  }

  if (args.check && args.force) {
    throw new Error("--check and --force cannot be used together");
  }

  return args;
}

function withGeneratedHeader(content) {
  const stripped = content.startsWith(GENERATED_HEADER)
    ? content.slice(GENERATED_HEADER.length)
    : content;
  return GENERATED_HEADER + stripped;
}

function maybeRenamePageFilename(relativePath) {
  return relativePath
    .replace(/^page\.(tsx|ts|jsx|js)$/u, "Page.$1")
    .replace(/\/page\.(tsx|ts|jsx|js)$/u, "/Page.$1");
}

const TEMPLATE_EXPORT_NAMES = {
  aiworkflow: "AIWorkflow",
  digitalagency: "DigitalAgency",
  gallery: "Gallery",
  productlaunch: "ProductLaunch",
  saasdashboard: "SaaSDashboard",
};

function getTemplateExportName(dirName) {
  return TEMPLATE_EXPORT_NAMES[dirName] ?? dirName;
}

function transformStyledJsx(content) {
  return content.replace(/<style\s+jsx>\{/gu, "<style>{");
}

function toPosixRelative(fromDir, toFile) {
  let rel = normalizePath(
    path.posix.relative(normalizePath(fromDir), normalizePath(toFile)),
  );
  if (!rel.startsWith(".")) rel = `./${rel}`;
  return rel;
}

function remapSpecifier(specifier, targetRelPath, targetKind) {
  const targetDir = path.posix.dirname(targetRelPath);

  if (specifier === "@/lib/utils") {
    return targetKind === "core"
      ? toPosixRelative(targetDir, "lib/utils")
      : "@nextworks/blocks-core";
  }

  if (specifier === "@/lib/themes") {
    return targetKind === "core"
      ? toPosixRelative(targetDir, "lib/themes")
      : "@nextworks/blocks-core/lib/themes";
  }

  if (specifier.startsWith("@/components/ui/")) {
    const leaf = specifier.slice("@/components/ui/".length);
    return targetKind === "core"
      ? toPosixRelative(targetDir, `ui/${leaf}`)
      : "@nextworks/blocks-core";
  }

  if (specifier.startsWith("@/components/sections/")) {
    return "@nextworks/blocks-sections";
  }

  return specifier;
}

function transformAliasImports(content, targetRelPath, targetKind) {
  return content.replace(
    /import\s+([\s\S]+?)\s+from\s+"(@\/[^"]+)";/gu,
    (_full, bindings, specifier) => {
      const remapped = remapSpecifier(specifier, targetRelPath, targetKind);
      return `import ${bindings} from "${remapped}";`;
    },
  );
}

function transformCoreImports(content, targetRelPath) {
  let transformed = transformAliasImports(content, targetRelPath, "core");

  transformed = transformed.replaceAll(
    'from "../enhanced-theme-provider"',
    'from "../components/enhanced-theme-provider"',
  );

  transformed = transformed.replaceAll(
    'import * as React from "react";',
    'import React from "react";',
  );

  transformed = transformed.replaceAll(
    'import { Button } from "../ui/button";',
    'import { Button } from "./button";',
  );
  transformed = transformed.replaceAll(
    'import { Card, CardContent } from "../ui/card";',
    'import { Card, CardContent } from "./card";',
  );
  transformed = transformed.replaceAll(
    'import { Card } from "../ui/card";',
    'import { Card } from "./card";',
  );
  transformed = transformed.replaceAll(
    'import { Button } from "../ui/button";\nimport { cn } from "../lib/utils";',
    'import { Button } from "./button";\nimport { cn } from "../lib/utils";',
  );

  if (targetRelPath === "providers/BlocksAppProviders.tsx") {
    transformed = transformed.replace(
      /import \{ EnhancedThemeProvider \} from "\.\.\/enhanced-theme-provider";/u,
      'import { EnhancedThemeProvider } from "../components/enhanced-theme-provider";',
    );
    transformed = transformed.replace(
      /import type \{ ThemeVariant \} from "\.\.\/\.\.\/lib\/themes";/u,
      'import type { ThemeVariant } from "../lib/themes";',
    );
  }

  if (targetRelPath === "lib/themes.ts") {
    transformed = transformed.replace(
      /export type \{ ThemeConfig, ThemeVariant \} from "@nextworks\/blocks-core";\s*import \{ type ThemeConfig, type ThemeVariant \} from "@nextworks\/blocks-core";\s*/u,
      'export type ThemeVariant =\n  | "default"\n  | "monochrome"\n  | "blue"\n  | "green"\n  | "purple"\n  | "orange"\n  | "custom";\n\nexport interface ThemeConfig {\n  name: string;\n  colors: {\n    primary: string;\n    primaryForeground: string;\n    secondary: string;\n    secondaryForeground: string;\n    accent: string;\n    accentForeground: string;\n    background: string;\n    foreground: string;\n    card: string;\n    cardForeground: string;\n    popover: string;\n    popoverForeground: string;\n    muted: string;\n    mutedForeground: string;\n    border: string;\n    input: string;\n    ring: string;\n    destructive: string;\n    chart1: string;\n    chart2: string;\n    chart3: string;\n    chart4: string;\n    chart5: string;\n  };\n}\n\n',
    );
  }

  return transformed;
}

function transformSectionsImports(content, targetRelPath) {
  return transformAliasImports(content, targetRelPath, "sections");
}

function transformTemplateImports(content, targetRelPath) {
  let transformed = transformAliasImports(content, targetRelPath, "templates");

  transformed = transformStyledJsx(transformed);

  transformed = transformed.replaceAll(
    '} from "@/components/sections/Contact";',
    '} from "@nextworks/blocks-sections";',
  );
  transformed = transformed.replaceAll(
    '} from "@/components/sections/Footer";',
    '} from "@nextworks/blocks-sections";',
  );
  transformed = transformed.replaceAll(
    '} from "@/components/sections/PortfolioSimple";',
    '} from "@nextworks/blocks-sections";',
  );

  if (
    targetRelPath.endsWith("/components/Hero.tsx") &&
    targetRelPath.includes("aiworkflow/")
  ) {
    transformed = transformed.replace(
      /import \{ HeroProductDemo \} from "@nextworks\/blocks-sections";\s*import type \{ ProductDemoScenario \} from "@nextworks\/blocks-sections";/u,
      'import { HeroProductDemo, type HeroProductDemoProps } from "@nextworks/blocks-sections";',
    );
    transformed = transformed.replace(
      /const scenarios: ProductDemoScenario\[\] = \[/u,
      'const scenarios: NonNullable<HeroProductDemoProps["stage"]>["scenarios"] = [',
    );
  }

  if (targetRelPath.endsWith("/Page.tsx")) {
    transformed = transformed.replace(
      /export default function /u,
      "export function ",
    );
  }

  return transformed;
}

function buildTargetPath(group, relativePath) {
  if (group === "core") {
    if (relativePath.startsWith("components/ui/")) {
      return relativePath.replace(/^components\//u, "");
    }
    if (relativePath === "components/enhanced-theme-provider.tsx") {
      return "components/enhanced-theme-provider.tsx";
    }
    if (relativePath === "components/providers/BlocksAppProviders.tsx") {
      return "providers/BlocksAppProviders.tsx";
    }
    if (relativePath === "lib/utils.ts") return "lib/utils.ts";
    if (relativePath === "lib/themes.ts") return "lib/themes.ts";
  }

  if (group === "sections") {
    return relativePath.replace(/^components\/sections\//u, "");
  }

  if (group === "templates") {
    return maybeRenamePageFilename(
      relativePath.replace(/^app\/templates\//u, ""),
    );
  }

  throw new Error(`Unhandled target mapping for ${group}:${relativePath}`);
}

function shouldSync(group, relativePath) {
  if (group === "core") {
    return (
      relativePath.startsWith("components/ui/") ||
      relativePath === "components/enhanced-theme-provider.tsx" ||
      relativePath === "components/providers/BlocksAppProviders.tsx" ||
      relativePath === "lib/utils.ts" ||
      relativePath === "lib/themes.ts"
    );
  }

  if (group === "sections") {
    return (
      relativePath.startsWith("components/sections/") &&
      !relativePath.endsWith("/index.ts") &&
      !relativePath.endsWith("index.ts")
    );
  }

  if (group === "templates") {
    return (
      relativePath.startsWith("app/templates/") &&
      /\.(ts|tsx|md)$/u.test(relativePath)
    );
  }

  return false;
}

const GROUPS = [
  {
    name: "core",
    sourceRoot: "cli/kits/blocks",
    targetRoot: "packages/blocks-core/src",
    transform: transformCoreImports,
  },
  {
    name: "sections",
    sourceRoot: "cli/kits/blocks",
    targetRoot: "packages/blocks-sections/src/components",
    transform: transformSectionsImports,
  },
  {
    name: "templates",
    sourceRoot: "cli/kits/blocks",
    targetRoot: "packages/blocks-templates/src/templates",
    transform: transformTemplateImports,
  },
];

async function writeGeneratedFile(targetFile, content) {
  await fs.mkdir(path.dirname(targetFile), { recursive: true });
  await fs.writeFile(targetFile, content, "utf8");
}

async function syncGroup(
  group,
  checkOnly,
  forceWrite = false,
  verbose = false,
) {
  const sourceRoot = path.join(repoRoot, group.sourceRoot);
  const targetRoot = path.join(repoRoot, group.targetRoot);
  const files = await walkFiles(sourceRoot);

  const relevantFiles = files.filter((file) => {
    const relativePath = normalizePath(path.relative(sourceRoot, file));
    return shouldSync(group.name, relativePath);
  });

  const results = [];

  for (const sourceFile of relevantFiles) {
    const sourceRelative = normalizePath(path.relative(sourceRoot, sourceFile));
    const targetRelative = buildTargetPath(group.name, sourceRelative);
    const targetFile = path.join(targetRoot, targetRelative);

    if (verbose) {
      console.log(` [${group.name}] ${sourceRelative} -> ${targetRelative}`);
    }

    const sourceContent = await fs.readFile(sourceFile, "utf8");
    const transformed = group.transform(sourceContent, targetRelative);
    const finalContent = /\.md$/u.test(targetRelative)
      ? transformed
      : withGeneratedHeader(transformed);
    const existingContent = (await exists(targetFile))
      ? await fs.readFile(targetFile, "utf8")
      : null;

    if (!forceWrite && existingContent === finalContent) {
      results.push({ status: "unchanged", targetRelative });
      continue;
    }

    if (checkOnly) {
      results.push({
        status: existingContent === null ? "missing" : "changed",
        targetRelative,
      });
      continue;
    }

    await writeGeneratedFile(targetFile, finalContent);
    results.push({
      status: forceWrite
        ? existingContent === null
          ? "created"
          : "overwritten"
        : existingContent === null
          ? "created"
          : "updated",
      targetRelative,
    });
  }

  return results;
}

async function syncTemplateIndex(checkOnly, forceWrite = false) {
  const templatesRoot = path.join(
    repoRoot,
    "packages/blocks-templates/src/templates",
  );
  const targetFile = path.join(
    repoRoot,
    "packages/blocks-templates/src/index.ts",
  );
  const entries = await fs.readdir(templatesRoot, { withFileTypes: true });

  const templateDirs = entries
    .filter((entry) => entry.isDirectory())
    .map((entry) => entry.name)
    .sort((a, b) => a.localeCompare(b));

  const lines = templateDirs.map((dirName) => {
    const exportName = getTemplateExportName(dirName);
    return `export * as ${exportName} from "./templates/${dirName}/Page";`;
  });

  const finalContent = `${lines.join("\n")}\n`;
  const existingContent = (await exists(targetFile))
    ? await fs.readFile(targetFile, "utf8")
    : null;

  if (!forceWrite && existingContent === finalContent) {
    return { status: "unchanged", targetRelative: "index.ts" };
  }

  if (checkOnly) {
    return {
      status: existingContent === null ? "missing" : "changed",
      targetRelative: "index.ts",
    };
  }

  await writeGeneratedFile(targetFile, finalContent);
  return {
    status: forceWrite
      ? existingContent === null
        ? "created"
        : "overwritten"
      : existingContent === null
        ? "created"
        : "updated",
    targetRelative: "index.ts",
  };
}

async function main() {
  const args = parseArgs(process.argv.slice(2));
  const groups =
    args.scope === "all"
      ? GROUPS
      : GROUPS.filter((group) => group.name === args.scope);

  let hasDrift = false;

  for (const group of groups) {
    const results = await syncGroup(
      group,
      args.check,
      args.force,
      args.verbose,
    );
    const changed = results.filter((result) => result.status !== "unchanged");

    console.log(
      `\n[${group.name}] ${changed.length} file(s) ${args.check ? "would change" : "changed"}`,
    );
    for (const result of changed) {
      console.log(` - ${result.status}: ${result.targetRelative}`);
    }

    if (args.check && changed.length > 0) hasDrift = true;
  }

  if (groups.some((group) => group.name === "templates")) {
    const indexResult = await syncTemplateIndex(args.check, args.force);
    const changed = indexResult.status !== "unchanged";

    console.log(
      `\n[templates:index] ${changed ? 1 : 0} file(s) ${args.check ? "would change" : "changed"}`,
    );
    if (changed) {
      console.log(` - ${indexResult.status}: ${indexResult.targetRelative}`);
    }

    if (args.check && changed) hasDrift = true;
  }

  if (args.check && hasDrift) {
    process.exitCode = 1;
  }
}

main().catch((error) => {
  console.error(error instanceof Error ? error.message : error);
  process.exitCode = 1;
});
